import './Zoom.scss';

import { IconButton } from ':components/IconButton';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import React from 'react';

export interface ZoomProps {
	onZoomIn: (event) => void;
	onZoomReset: (event) => void;
	onZoomOut: (event) => void;
}

export const Zoom = ({ onZoomIn, onZoomOut, onZoomReset }: ZoomProps) => (
	<div className="dsb_preview__zoom">
		<IconButton iconName={Icons.Add} variant="base" onClick={onZoomIn} />
		<IconButton iconName={Icons.ZoomIn} variant="base" onClick={onZoomReset} />
		<IconButton iconName={Icons.Remove} variant="base" onClick={onZoomOut} />
	</div>
);
